package org.jsoup.parser;

import io.cucumber.junit.Cucumber;
import io.cucumber.junit.CucumberOptions;
import org.junit.runner.RunWith;

@RunWith(Cucumber.class)
@CucumberOptions(
    features = "src/test/resources/requirement.feature",
    glue = "org.jsoup.parser.steps"
)
public class CucumberTest {
}

package org.jsoup.parser.steps;

import io.cucumber.java.en.Given;
import io.cucumber.java.en.When;
import io.cucumber.java.en.Then;
import org.jsoup.Jsoup;
import org.jsoup.nodes.Document;
import org.jsoup.parser.Parser;
import org.jsoup.nodes.Element;

import static org.junit.Assert.*;

public class StepDefs {
    private Document document;
    private String inputHtml;
    private Parser parser;
    private boolean preserveCase;

    @Given("the HTML parser is configured with \"preserveCase\" set to true")
    public void the_html_parser_is_configured_with_preserveCase_set_to_true() {
        preserveCase = true;
    }

    @Given("the input HTML is {string}")
    public void the_input_html_is(String html) {
        inputHtml = html;
    }

    @When("the document is parsed")
    public void the_document_is_parsed() {
        try {
            // Using the same approach as the original test
            // Parser.htmlParser() with preserveCase setting
            org.jsoup.parser.Parser parser = org.jsoup.parser.Parser.htmlParser();
            parser.settings(org.jsoup.parser.ParseSettings.preserveCase);
            document = parser.parseInput(inputHtml, "");
        } catch (Exception e) {
            // If there's an exception during parsing, capture it
            fail("Exception occurred during parsing: " + e.getMessage());
        }
    }

    @Then("the resulting body HTML should match {string}")
    public void the_resulting_body_html_should_match(String expected) {
        // Use the same normalization as the original test
        String actualHtml = document.body().html();
        String normalizedActual = org.jsoup.helper.StringUtil.normaliseWhitespace(actualHtml);
        String normalizedExpected = org.jsoup.helper.StringUtil.normaliseWhitespace(expected);

        assertEquals("The normalized HTML should match", normalizedExpected, normalizedActual);
    }
}

